using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly ModelTrainingService _trainingService;

    public TicketsController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        ModelTrainingService trainingService)
    {
        _predictionPool = predictionPool;
        _trainingService = trainingService;
    }

    [HttpPost("classify")]
    public ActionResult<PredictionResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        string[] labels = ["Billing", "General", "Technical"];
        var scores = new Dictionary<string, float>();
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
        {
            scores[labels[i]] = prediction.Score[i];
        }

        return Ok(new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Scores = scores
        });
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        if (_trainingService.Metrics is null)
            return NotFound("Model has not been trained yet.");

        return Ok(_trainingService.Metrics);
    }
}

